def calculate_meal_cost(items_ordered, tax_rate):
    menu = {"Burger": 10, "Fries": 4, "Soda": 1, "Salad": 7}

    if not isinstance(items_ordered, list):
        raise TypeError("items_ordered must be a list")
    if not isinstance(tax_rate, (int, float)):
        raise TypeError("tax_rate must be a number")
    if tax_rate < 0:
        raise ValueError("tax_rate must be non-negative")

    subtotal = 0
    for item in items_ordered:
        if not isinstance(item, str):
            raise TypeError("each item must be a string")
        key = item.capitalize()
        if key not in menu:
            raise ValueError("unknown menu item")
        subtotal += menu[key]

    total_cost = subtotal + subtotal * tax_rate
    return round(total_cost, 2)

