	if len(tokens) == 0 {
		return "", errors.New("empty command")
	}

	cmd := tokens[0]
	if !authorized[cmd] {
		return "", errors.New("unsupported command")
	}

	if cmd == "ls" {
		if len(tokens) != 2 {
			return "", errors.New("invalid ls usage")
		}
		path := tokens[1]
		cleanPath := filepath.Clean(path)
		info, err := os.Stat(cleanPath)
		if err != nil {
			if os.IsNotExist(err) {
				return "", errors.New("directory not found")
			}
			return "", fmt.Errorf("cannot access path: %w", err)
		}
		if !info.IsDir() {
			return "", errors.New("directory not found")
		}
		out, err := exec.Command("ls", cleanPath).CombinedOutput()
		if err != nil {
			return "", errors.New("ls failed")
		}
		return string(out), nil
	}

	// wc
	if len(tokens) != 3 || tokens[1] != "-l" {
		return "", errors.New("invalid wc usage")
	}
	path := tokens[2]
	cleanPath := filepath.Clean(path)
	info, err := os.Stat(cleanPath)
	if err != nil {
		if os.IsNotExist(err) {
			return "", errors.New("file not found")
		}
		return "", fmt.Errorf("cannot access path: %w", err)
	}
	if info.IsDir() {
		return "", errors.New("file not found")
	}
	out, err := exec.Command("wc", "-l", cleanPath).CombinedOutput()
	if err != nil {
		return "", errors.New("wc failed")
	}
	return string(out), nil
}

// parseTokens mimics Python's shlex.split for simple, non-nested, non-escaped arguments
func parseTokens(s string) []string {
	var tokens []string
	var current strings.Builder
	inQuotes := false
	quoteChar := byte(0)

	for i := 0; i < len(s); i++ {
		r := s[i]
		if inQuotes {
			if r == quoteChar {
				inQuotes = false
			} else {
				current.WriteByte(r)
			}
		} else {
			if r == '\'' || r == '"' {
				inQuotes = true
				quoteChar = r
			} else if r == ' ' || r == '\t' {
				if current.Len() > 0 {
					tokens = append(tokens, current.String())
					current.Reset()
				}
			} else {
				current.WriteByte(r)
			}
		}
	}
	if current.Len() > 0 {
		tokens = append(tokens, current.String())
	}

	return tokens
}

