type Question struct {
	Question      string   `json:"question"`
	Options       []string `json:"options"`
	CorrectOption string   `json:"correct_option"`
}

// escapeHTML escapes HTML special characters, matching Python's html.escape behavior for quotes.
func escapeHTML(s string) string {
	return strings.ReplaceAll(html.EscapeString(s), "&#34;", "&quot;")
}

// create_question creates a Question struct with HTML-escaped fields.
func create_question(question string, options []string, correctOption string) (*Question, error) {
	if len(options) == 0 {
		return nil, errors.New("options must be a non-empty list")
	}

	validCorrect := false
	for _, opt := range options {
		if opt == correctOption {
			validCorrect = true
			break
		}
	}
	if !validCorrect {
		return nil, errors.New("correct_option must be in options")
	}

	encodedQuestion := escapeHTML(question)
	encodedOptions := make([]string, len(options))
	for i, opt := range options {
		encodedOptions[i] = escapeHTML(opt)
	}
	encodedCorrect := escapeHTML(correctOption)

	return &Question{
		Question:      encodedQuestion,
		Options:       encodedOptions,
		CorrectOption: encodedCorrect,
	}, nil
}

