func htmlEscape(s string, escapeQuotes bool) string {
	var buf []rune
	for _, c := range s {
		switch c {
		case '&':
			buf = append(buf, '&', 'a', 'm', 'p', ';')
		case '<':
			buf = append(buf, '&', 'l', 't', ';')
		case '>':
			buf = append(buf, '&', 'g', 't', ';')
		case '"':
			if escapeQuotes {
				buf = append(buf, '&', 'q', 'u', 'o', 't', ';')
			} else {
				buf = append(buf, c)
			}
		case '\'':
			if escapeQuotes {
				buf = append(buf, '&', '#', '3', '9', ';')
			} else {
				buf = append(buf, c)
			}
		default:
			buf = append(buf, c)
		}
	}
	return string(buf)
}

